Here's a minimal API endpoint handling multipart form uploads with multiple images and a description:

```csharp
using Microsoft.AspNetCore.Http.Features;

var builder = WebApplication.CreateBuilder(args);

// Raise the max request body size to 50 MB
builder.WebHost.ConfigureKestrel(o =>
    o.Limits.MaxRequestBodySize = 50 * 1024 * 1024);

var app = builder.Build();

app.MapPost("/upload", async (HttpRequest request) =>
{
    // Ensure it's a multipart form request
    if (!request.HasFormContentType)
        return Results.BadRequest("Expected a multipart/form-data request.");

    var form = await request.ReadFormAsync();

    var description = form["description"].ToString();
    var files = form.Files.GetFiles("images"); // matches <input name="images">

    if (files.Count == 0)
        return Results.BadRequest("No images provided.");

    var saved = new List<string>();
    var uploadDir = Path.Combine(Directory.GetCurrentDirectory(), "uploads");
    Directory.CreateDirectory(uploadDir);

    foreach (var file in files)
    {
        // Basic validation
        if (!file.ContentType.StartsWith("image/"))
            return Results.BadRequest($"'{file.FileName}' is not an image.");

        var safeName = $"{Guid.NewGuid()}{Path.GetExtension(file.FileName)}";
        var path = Path.Combine(uploadDir, safeName);

        await using var stream = File.Create(path);
        await file.CopyToAsync(stream);

        saved.Add(safeName);
    }

    return Results.Ok(new { description, fileCount = saved.Count, saved });
})
.DisableAntiforgery()                 // needed when no auth middleware
.Accepts<IFormFile>("multipart/form-data");

app.Run();
```

**Key points:**

- **`ConfigureKestrel`** sets the 50 MB limit. If behind IIS/Nginx you must also raise limits there.
- **`form.Files.GetFiles("images")`** pulls all files uploaded under the `images` field name.
- **`DisableAntiforgery()`** is required for minimal APIs accepting forms without antiforgery middleware; remove it if you wire up antiforgery.
- Each file gets a GUID name to avoid path-traversal or collision issues.

**Test with `curl`:**

```bash
curl -X POST http://localhost:5000/upload \
  -F "description=Vacation photos" \
  -F "images=@photo1.jpg" \
  -F "images=@photo2.png"
```
